#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
const int b=131,maxn=1e6+5;
int h[maxn],p[maxn];
char stk[maxn];
void init_hash(const string &s) {
	int n=s.length();
	p[0]=1;
	for(int i=1; i<=n; i++) {
		p[i]=p[i-1]*b;
	}
}
int get_hash(int l,int r) {
	return h[r]-h[l-1]*p[r-l+1];
}
int n,hf;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	string s,t;
	cin>>s>>t;
	int len=t.length();
	init_hash(s);
	for(char c:t){
		hf=hf*b+c;
	}
	int top=0;
	for(char c:s){
		stk[++top]=c;
		h[top]=h[top-1]*b+c;
		if(top>=len&&get_hash(top-len+1,top)==hf){
			top-=len;
		}
	}
	for(int i=1;i<=top;i++){
		cout<<stk[i];
	}
	return 0;
}
